const md = $input.first().json.html_content || "";

// ---------- CLEAN ----------
const clean = (s) => s
  .replace(/\*\*(.*?)\*\*/g, '$1')
  .replace(/\[(.*?)\]\((.*?)\)/g, '$1')
  .trim();

// ---------- SPLIT ----------
const lines = md.split('\n').map(l => l.trim()).filter(Boolean);

// ---------- STORAGE ----------
let name = '';
let contact = '';

const experience = [];
const projects = [];
const skills = [];
const education = [];

let section = "";

// ---------- PARSE ----------
for (let i = 0; i < lines.length; i++) {
  const l = clean(lines[i]);

  // NAME
  if (l.startsWith("NAME:")) {
    name = l.replace("NAME:", "").trim();
    continue;
  }

  // CONTACT
  if (l.startsWith("CONTACT:")) {
    contact = clean(lines[i + 1] || "");
    continue;
  }

  // SECTION SWITCH
  if (l.startsWith("EXPERIENCE")) section = "exp";
  else if (l.startsWith("PROJECTS")) section = "proj";
  else if (l.startsWith("TECHNICAL_SKILLS")) section = "skills";
  else if (l.startsWith("EDUCATION")) section = "edu";

  // ---------- EXPERIENCE ----------
  if (section === "exp" && l.startsWith("- Role:")) {
    let role = l.replace("- Role:", "").trim();
    let company = clean(lines[++i]?.replace("Company:", "") || "");
    let duration = clean(lines[++i]?.replace("Duration:", "") || "");

    let bullets = [];

    // skip "Points:"
    if (lines[i + 1]?.includes("Points")) i++;

    while (lines[i + 1] && lines[i + 1].trim().startsWith("-")) {
      bullets.push(clean(lines[++i].replace(/^-/, '')));
    }

    experience.push({ role, company, duration, bullets });
  }

  // ---------- PROJECTS ----------
  if (section === "proj" && l.startsWith("- Title:")) {
    let title = l.replace("- Title:", "").trim();
    let year = clean(lines[++i]?.replace("Year:", "") || "");

    let bullets = [];

    // skip "Points:"
    if (lines[i + 1]?.includes("Points")) i++;

    while (lines[i + 1] && lines[i + 1].trim().startsWith("-")) {
      bullets.push(clean(lines[++i].replace(/^-/, '')));
    }

    projects.push({ title, year, bullets });
  }

  // ---------- SKILLS ----------
  if (section === "skills" && l.startsWith("-")) {
    skills.push(clean(l.replace(/^-/, '')));
  }

  // ---------- EDUCATION ----------
  if (section === "edu" && l.startsWith("-")) {
    education.push(clean(l.replace(/^-/, '')));
  }
}

// ---------- RENDER ----------
function renderExp(arr) {
  return arr.map(item => `
    <div class="item">
      <div class="title">${item.role}</div>
      <div class="sub">${item.company} · ${item.duration}</div>
      <ul>
        ${item.bullets.map(b => `<li>${b}</li>`).join('')}
      </ul>
    </div>
  `).join('');
}

function renderProj(arr) {
  return arr.map(item => `
    <div class="item">
      <div class="title">${item.title} | ${item.year}</div>
      <ul>
        ${item.bullets.map(b => `<li>${b}</li>`).join('')}
      </ul>
    </div>
  `).join('');
}

function renderList(arr) {
  return arr.length
    ? `<ul>${arr.map(i => `<li>${i}</li>`).join('')}</ul>`
    : '';
}

// ---------- HTML ----------
const html = `
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
  body {
    font-family: Arial;
    margin: 26px;
    font-size: 11px;
    line-height: 1.5;
    color: #111;
    max-width: 800px;
  }

  h1 {
    margin: 0;
    font-size: 17px;
  }

  .contact {
    font-size: 10px;
    margin: 5px 0 10px;
    color: #444;
  }

  .section {
    margin-top: 10px;
  }

  .section h2 {
    font-size: 11px;
    text-transform: uppercase;
    border-bottom: 1px solid #000;
    margin-bottom: 4px;
  }

  .item {
    margin-bottom: 6px;
  }

  .title {
    font-weight: bold;
    font-size: 10.5px;
  }

  .sub {
    font-size: 9.5px;
    color: #555;
    margin-bottom: 2px;
  }

  ul {
    margin: 2px 0 5px 14px;
  }

  li {
    margin-bottom: 2px;
  }
</style>
</head>

<body>

<h1>${name}</h1>
<div class="contact">${contact.replace(/\|/g, ' | ')}</div>

<div class="section">
<h2>Experience</h2>
${renderExp(experience)}
</div>

<div class="section">
<h2>Projects</h2>
${renderProj(projects)}
</div>

<div class="section">
<h2>Skills</h2>
${renderList(skills)}
</div>

<div class="section">
<h2>Education</h2>
${renderList(education)}
</div>

</body>
</html>
`;

return [{ json: { html } }];
